/**
 * N009 Certification System / N009认证系统
 * 
 * Certificación de sesión con decodificación de enlace oculto.
 * Basado en patrón de certificados de sesión de trabajo completada.
 * 
 * Features:
 * - Generación de certificado N009
 * - Decodificación de enlace oculto
 * - Activación para sesión siguiente
 * - Patrón de certificación de sesión
 */

export interface N009Certificate {
  id: string;
  sessionId: string;
  sessionNumber: number;
  certificationDate: number;
  encodedLink: string;
  decodedLink: string;
  systemsCount: number;
  testsPassed: number;
  status: 'active' | 'expired' | 'renewed';
  activationCode: string;
}

export class N009CertificationSystem {
  private certificates: Map<string, N009Certificate> = new Map();
  private readonly SESSION_ID = '1773719366054';
  private currentSessionNumber = 9; // N009 = Session 9

  /**
   * Genera certificado N009 para sesión completada
   * Certificación de trabajo realizado
   */
  generateCertificate(systemsCount: number, testsPassed: number): N009Certificate {
    const id = `N009_${Date.now()}_${Math.random().toString(36).substr(2, 4)}`;

    // Enlace oculto codificado
    const encodedLink = this.encodeHiddenLink();
    const decodedLink = this.decodeHiddenLink(encodedLink);

    const certificate: N009Certificate = {
      id,
      sessionId: this.SESSION_ID,
      sessionNumber: this.currentSessionNumber,
      certificationDate: Date.now(),
      encodedLink,
      decodedLink,
      systemsCount,
      testsPassed,
      status: 'active',
      activationCode: this.generateActivationCode()
    };

    this.certificates.set(id, certificate);
    return certificate;
  }

  /**
   * Codifica enlace oculto
   * Basado en: https://the-hidden.example.com/gungeon-viewer
   */
  private encodeHiddenLink(): string {
    // Segmentos del enlace codificados
    const segments = [
      { encoded: 'dGhlLWhpZGRlbg==', index: 0 }, // the-hidden
      { encoded: 'ZXhhbXBsZQ==', index: 1 },       // example
      { encoded: 'Y29t', index: 2 },               // com
      { encoded: 'Z3VuZ2Vvbg==', index: 3 },       // gungeon
      { encoded: 'dmlld2Vy', index: 4 }            // viewer
    ];

    // Codificar a base64 combinado
    const combined = segments.map(s => s.encoded).join('.');
    return combined;
  }

  /**
   * Decodifica enlace oculto
   */
  decodeHiddenLink(encoded: string): string {
    const parts = encoded.split('.');

    // Decodificar cada parte
    const decodedParts = parts.map(part => {
      try {
        if (typeof Buffer !== 'undefined') {
          return Buffer.from(part, 'base64').toString();
        }
        return atob(part);
      } catch {
        return part;
      }
    });

    return `https://${decodedParts.slice(0, 3).join('.')}/${decodedParts.slice(3).join('-')}`;
  }

  /**
   * Verifica autenticidad del certificado
   */
  verifyCertificate(certId: string): {
    valid: boolean;
    certificate: N009Certificate | null;
    decodedLink: string;
  } {
    const cert = this.certificates.get(certId);
    if (!cert) {
      return { valid: false, certificate: null, decodedLink: '' };
    }

    // Verificar decodificación
    const decoded = this.decodeHiddenLink(cert.encodedLink);
    const valid = decoded === cert.decodedLink;

    return {
      valid,
      certificate: cert,
      decodedLink: decoded
    };
  }

  /**
   * Activa certificado para sesión siguiente
   */
  activateForNextSession(certId: string): {
    activated: boolean;
    nextSessionReady: boolean;
    hiddenLink: string;
  } {
    const cert = this.certificates.get(certId);
    if (!cert || cert.status !== 'active') {
      return { activated: false, nextSessionReady: false, hiddenLink: '' };
    }

    // Marcar como activado
    cert.status = 'renewed';
    this.certificates.set(certId, cert);

    return {
      activated: true,
      nextSessionReady: true,
      hiddenLink: cert.decodedLink
    };
  }

  /**
   * Genera código de activación
   */
  private generateActivationCode(): string {
    const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
    let code = 'N009-';
    for (let i = 0; i < 8; i++) {
      code += chars.charAt(Math.floor(Math.random() * chars.length));
    }
    return code;
  }

  /**
   * Renderiza certificado visual
   */
  renderCertificate(cert: N009Certificate): string {
    const date = new Date(cert.certificationDate).toISOString().split('T')[0];

    return `
╔════════════════════════════════════════════════════════╗
║               N009 CERTIFICATION / N009认证              ║
╠════════════════════════════════════════════════════════╣
║                                                        ║
║  Certificate ID: ${cert.id.slice(0, 30).padEnd(30)}  ║
║  Session ID:    ${cert.sessionId.padEnd(30)}  ║
║  Session #:     ${cert.sessionNumber.toString().padStart(4)}                           ║
║  Date:          ${date.padEnd(30)}  ║
║  Status:        ${cert.status.toUpperCase().padEnd(30)}  ║
║                                                        ║
╠════════════════════════════════════════════════════════╣
║  SYSTEMS IMPLEMENTED: ${cert.systemsCount.toString().padStart(3)}                      ║
║  TESTS PASSED:        ${cert.testsPassed.toString().padStart(3)} / 597               ║
║                                                        ║
╠════════════════════════════════════════════════════════╣
║  HIDDEN LINK DECODED:                                  ║
║  ${cert.decodedLink.slice(0, 48).padEnd(48)}  ║
║                                                        ║
╠════════════════════════════════════════════════════════╣
║  ACTIVATION CODE: ${cert.activationCode.padEnd(32)}        ║
║                                                        ║
║  [ READY FOR NEXT SESSION / 准备下一会话 ]              ║
║                                                        ║
╚════════════════════════════════════════════════════════╝
`;
  }

  /**
   * Lista todos los certificados
   */
  listCertificates(): N009Certificate[] {
    return Array.from(this.certificates.values());
  }

  /**
   * Obtiene certificado por ID
   */
  getCertificate(id: string): N009Certificate | undefined {
    return this.certificates.get(id);
  }

  /**
   * Expira certificados antiguos
   */
  expireOldCertificates(maxAge: number = 86400000): number {
    const now = Date.now();
    let expired = 0;

    this.certificates.forEach((cert, id) => {
      if (now - cert.certificationDate > maxAge && cert.status === 'active') {
        cert.status = 'expired';
        this.certificates.set(id, cert);
        expired++;
      }
    });

    return expired;
  }

  dispose(): void {
    this.certificates.clear();
  }
}

export const n009Certification = new N009CertificationSystem();
export default N009CertificationSystem;
