      const encoded = '\\u003cdiv\\u003e';
      const decoded = system.decodeSessionHTML(encoded);
      expect(decoded).toBe('<div>');
    });

    it('decodes &lt; and &gt;', () => {
      const encoded = '&lt;p&gt;text&lt;/p&gt;';
      const decoded = system.decodeSessionHTML(encoded);
      expect(decoded).toBe('<p>text</p>');
    });

    it('decodes &#xXX; hex entities', () => {
      const encoded = '&#x3c;test&#x3e;';
      const decoded = system.decodeSessionHTML(encoded);
      expect(decoded).toBe('<test>');
    });

    it('decodes &#XX; decimal entities', () => {
      const encoded = '&#60;test&#62;';
      const decoded = system.decodeSessionHTML(encoded);
      expect(decoded).toBe('<test>');
    });

    it('decodes mixed entities', () => {
      const encoded = '\\u003cdiv\\u003e&amp;&quot;\\u003c/div\\u003e';
      const decoded = system.decodeSessionHTML(encoded);
      expect(decoded).toBe('<div>&"</div>');
    });

    it('handles plain text', () => {
      const text = 'hello world';
      const decoded = system.decodeSessionHTML(text);
      expect(decoded).toBe('hello world');
    });
  });

