      const session = system.createSession(html);

      expect(session.highlights.length).toBeGreaterThan(0);
      expect(session.highlights).toContain('important');
    });
  });

  describe('Assist in Highlights', () => {
    it('assists highlight', () => {
      const session = system.createSession('test data');
      const success = system.assistHighlight(session.sessionId, 'feature');

      expect(success).toBe(true);

      const updated = system.getSession(session.sessionId);
      expect(updated?.assists).toBe(1);
      expect(updated?.highlights).toContain('feature');
    });

    it('increments assist counter', () => {
      const session = system.createSession('data');

      system.assistHighlight(session.sessionId, 'h1');
      system.assistHighlight(session.sessionId, 'h2');

      const updated = system.getSession(session.sessionId);
      expect(updated?.assists).toBe(2);
    });

    it('fails for non-existent session', () => {
      const success = system.assistHighlight('INVALID', 'highlight');
      expect(success).toBe(false);
    });
  });

