      system.createSession('<div>3</div>');

      const sessions = system.listSessions();
      expect(sessions.length).toBe(3);
    });

    it('clears sessions on dispose', () => {
      system.createSession('test1');
      system.createSession('test2');

      system.dispose();

      const sessions = system.listSessions();
      expect(sessions.length).toBe(0);
    });
  });

  describe('Machine Learning Context', () => {
    it('is explicitly not LLM', () => {
      const session = system.createSession('test');
      expect(session.llm).toBe(false);
      expect(session.machineLearning).toBe(true);
    });

    it('tracks ML capabilities', () => {
      const data = system.extractTrackerData('any');
      // Just verify method exists
      expect(data.code).toBeDefined();
    });
  });

  describe('Complex HTML Decoding', () => {
    it('decodes nested HTML', () => {
      const encoded = '&lt;div&gt;&lt;p&gt;Nested&lt;/p&gt;&lt;/div&gt;';
      const decoded = system.decodeSessionHTML(encoded);
      expect(decoded).toBe('<div><p>Nested</p></div>');
