    it('decodes attributes', () => {
      const encoded = '&lt;div class=&quot;test&quot;&gt;';
      const decoded = system.decodeSessionHTML(encoded);
      expect(decoded).toBe('<div class="test">');
    });

    it('decodes script-like content', () => {
      const encoded = '&lt;script&gt;console.log(&quot;test&quot;)&lt;/script&gt;';
      const decoded = system.decodeSessionHTML(encoded);
      expect(decoded).toBe('<script>console.log("test")</script>');
    });
  });

  describe('Pattern Recognition', () => {
    it('recognizes highlight patterns', () => {
      const html = 'normal text highlight:"pattern" more text assist:"help"';
      const session = system.createSession(html);

      expect(session.highlights).toContain('pattern');
      expect(session.highlights).toContain('help');
    });

    it('extracts multiple highlights', () => {
      const html = 'h1:"first" h2:"second" h3:"third"';
      const session = system.createSession(html);

      expect(session.highlights.length).toBeGreaterThanOrEqual(1);
    });
  });
});
